function v029Hash(value){let h=2166136261;for(const ch of String(value)){h^=ch.charCodeAt(0);h=Math.imul(h,16777619);}return h>>>0;}
function v029Rng(seed){let x=(Number(seed)>>>0)||1;return()=>{x=(Math.imul(1664525,x)+1013904223)>>>0;return x/4294967296;};}
function v029Money(value){return typeof moneyV019==="function"?moneyV019(value):new Intl.NumberFormat("es-ES",{style:"currency",currency:"EUR",maximumFractionDigits:0}).format(value||0);}
function v029Percent(value){return `${Math.round(toNum(value,0))}%`;}
function v029LevelClass(value){return value>=80?"excellent":value>=65?"good":value>=45?"watch":"critical";}
function v029TeamYear(){return Number(getTeam(Game.selectedTeamId)?.season||Game.historical?.selectedYear||2026);}
function v029TeamLevel(){return String(getTeam(Game.selectedTeamId)?.level||"PRO").toUpperCase();}
function v029FacilityCost(def,nextLevel){return Math.round(def.baseCost*Math.pow(def.levelFactor,Math.max(0,nextLevel-1)));}
function v029FacilityOpex(def,level){return level?Math.round(def.baseOpex*Math.pow(1.55,Math.max(0,level-1))):0;}
function v029FacilityEffect(key){const club=ensureV029State();return V029_FACILITIES.reduce((sum,def)=>sum+toNum(def.effects?.[key],0)*toNum(club.campus.facilities[def.id]?.level,0),0);}

function v029DefaultHeadquarters(team){
  const name=String(team?.name||"").toLowerCase(),country=String(team?.country||"").toLowerCase();
  if(name.includes("movistar")||name.includes("banesto")||name.includes("once")||country.includes("espa"))return name.includes("eusk")||name.includes("once")?"bilbao":"girona";
  if(name.includes("uae")||country.includes("emir"))return"dubai";
  if(name.includes("ineos")||name.includes("sky")||country.includes("reino"))return"manchester";
  if(name.includes("visma")||name.includes("rabobank")||country.includes("países")||country.includes("netherlands"))return"eindhoven";
  if(name.includes("telekom")||name.includes("t-mobile")||name.includes("bora")||country.includes("alem"))return"munich";
  if(name.includes("quick")||name.includes("lotto")||country.includes("bélg")||country.includes("belg"))return"oudenaarde";
  if(name.includes("astana"))return"andorra";
  if(country.includes("ital")||name.includes("saunier")||name.includes("kelme"))return"milan";
  if(country.includes("fran")||name.includes("cofidis"))return"nice";
  if(country.includes("dina"))return"copenhagen";
  if(country.includes("colom"))return"bogota";
  if(country.includes("austr"))return"adelaide";
  return"girona";
}

function v029DefaultFacilityLevel(def,team){
  const year=Number(team?.season||2026),level=String(team?.level||"PRO").toUpperCase();
  let base=level==="WT"?2:level.includes("PRO")?1:0;
  if(year<2000)base=Math.max(0,base-1);
  if(year<2010&&["aero_center","scouting_center","commercial_media"].includes(def.id))base=Math.max(0,base-1);
  if(def.id==="hospitality_museum")base=level==="WT"&&year>=2015?1:0;
  if(def.id==="performance"&&level==="WT"&&year>=2020)base=3;
  return clamp(base,0,def.max);
}

function v029LegacySponsor(team){
  const name=String(team?.displayName||team?.name||"Club Cycling");
  const base=name.split(/[-–—]/)[0].trim();
  const level=String(team?.level||"PRO").toUpperCase();
  const fixed=level==="WT"?11500000:level.includes("PRO")?5200000:2100000;
  return {id:`legacy_${team?.id||"team"}`,companyId:null,companyName:base,type:"title",sectorId:"legacy",country:team?.country||"International",fixedAnnual:fixed,signingBonus:0,variablePool:Math.round(fixed*.18),duration:3,remainingYears:3,nameRights:false,colorRights:false,activationDays:5,markets:[team?.country||"Local"],objective:"Mantener la categoría y maximizar la exposición",satisfaction:76,exclusivity:"legacy",status:"active",historical:true,startedYear:v029TeamYear()};
}

function v029InitialFans(team,prestige){
  const total=Math.round((String(team?.level||"").toUpperCase()==="WT"?520000:180000)*(0.65+prestige/100));
  const home=String(team?.country||"Otros");
  const regions=Object.fromEntries(V029_FAN_REGIONS.map(r=>[r,Math.round(total*.035)]));
  const map=home.includes("Esp")?"España":home.includes("Fra")?"Francia":home.includes("Ale")?"Alemania":home.includes("Bel")||home.includes("Bél")?"Bélgica":home.includes("Ital")?"Italia":home.includes("País")?"Países Bajos":home.includes("Reino")?"Reino Unido":home.includes("Col")?"Latinoamérica":"Otros";
  regions[map]=Math.round(total*.58);regions.Otros=Math.max(regions.Otros,Math.round(total*.12));
  const sum=Object.values(regions).reduce((a,b)=>a+b,0)||1;
  Object.keys(regions).forEach(k=>regions[k]=Math.round(regions[k]*total/sum));
  return regions;
}

