    if(!Game.v029.sponsors.contracts.length&&team)Game.v029.sponsors.contracts.push(v029LegacySponsor(team));
    Game.v029.brand ||= {identityId:level==="WT"?"international":"budget_efficiency",commercialName:team?.displayName||team?.name||"Cycling Team",originalTeamName:team?.name||"Cycling Team",originalDisplayName:team?.displayName||team?.name||"Cycling Team",primaryColor:team?.visual?.primary||"#0a84ff",secondaryColor:team?.visual?.secondary||"#161a20",accentColor:team?.visual?.accent||"#30d158",fansByRegion:v029InitialFans(team,prestige),merchandisingPrice:79,contentIntensity:50,reputation:prestige,identityChanges:0};
    Game.v029.organization ||= {assignments:{},departmentMorale:78,workload:55,leadershipStability:76};
    Game.v029.media ||= {exposurePoints:0,seasonExposure:0,history:[],socialFollowers:Math.round(Object.values(Game.v029.brand.fansByRegion||{}).reduce((a,b)=>a+b,0)*.72),contentLibrary:0,viralHits:0};
    Game.v029.finances ||= {ledger:[],debt:0,creditLimit:level==="WT"?12000000:5000000,interestRate:0.055,merchandisingRevenue:0,hospitalityRevenue:0,prizeRevenue:0,otherRevenue:0,lastProjection:null,monthIndex:0};
    Game.v029.events ||= {pending:null,history:[],raceProcessed:{},discounts:{relocation:0,facility:0}};
    Game.v029.ui ||= {section:"summary"};
    if(Game.manager&&!Number.isFinite(Game.manager.budget))Game.manager.budget=level==="WT"?36000000:10500000;
    v029GenerateSponsorOffers(false);
    v029ApplyBranding();
